1	export function nextGeneration(grid: boolean[][]): boolean[][] {
2	  if (grid.length === 0) return [];
3	
4	  const rows = grid.length;
5	  const cols = grid[0].length;
6	
7	  const countNeighbors = (r: number, c: number): number => {
8	    let count = 0;
9	    for (let dr = -1; dr <= 1; dr++) {
10	      for (let dc = -1; dc <= 1; dc++) {
11	        if (dr === 0 && dc === 0) continue;
12	        const nr = r + dr;
13	        const nc = c + dc;
14	        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) {
15	          count++;
16	        }
17	      }
18	    }
19	    return count;
20	  };
21	
22	  const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
23	  const isReborn = (neighbors: number): boolean => neighbors === 3;
24	
25	  const next = grid.map((row, r) =>
26	    row.map((cell, c) => {
27	      const neighbors = countNeighbors(r, c);
28	      return cell ? survives(neighbors) : isReborn(neighbors);
29	    })
30	  );
31	
32	  const hasLiveCell = next.some(row => row.some(cell => cell));
33	  return hasLiveCell ? next : [];
34	}
